function rarityRole(mon) {
  const d = mon.dex;
  if (d <= 9) return "starter line / one-of-a-kind rare";
  if ([144,145,146].includes(d)) return "legendary bird equivalent / one-of-a-kind";
  if (d === 150) return "Mewtwo replacement / boss legendary";
  if (d === 151) return "Mew replacement / mythic secret";
  if ([138,139,140,141,142].includes(d)) return "fossil or ancient rare";
  if ([106,107].includes(d)) return "dojo choice rare";
  if ([113,115,122,123,124,125,126,127,128,131,132,133,134,135,136,137].includes(d)) return "special or uncommon single-stage slot";
  if (d === 143) return "static roadblock rare";
  if ([25,26,35,36,37,38,39,40,52,53,77,78,83,84,85].includes(d)) return "uncommon or version-style encounter";
  if (d >= 147 && d <= 149) return "late-game dragon/apex rare line";
  if (d <= 24) return "early route common line";
  return "standard encounter / normal dex slot";
}

function evolutionStage(mon) {
  if (mon.dex <= 9) return [1,4,7].includes(mon.dex) ? "starter base form" : [2,5,8].includes(mon.dex) ? "middle starter evolution" : "final starter evolution";
  if ((mon.notes || "").toLowerCase().includes("final")) return "final evolution";
  if (mon.evolvesInto && mon.nextEvolution && mon.nextEvolution !== "None") return "base form of 3-stage line";
  if (mon.evolvesInto) return "base form of 2-stage line";
  return "single-stage or final form";
}

function splitTypes(typeString) { return String(typeString || "").split('/').map(t => t.trim()).filter(Boolean); }

function typeMotifText(typeString) {
  return splitTypes(typeString).map(t => `${t}: ${typeMotifs[t] || "original visual motif"}`).join("; ");
}

function populateSpecies() {
  $("speciesSelect").innerHTML = LOGANMON.map(mon => `<option value="${mon.dex}">#${String(mon.dex).padStart(3,'0')} ${mon.name} — ${mon.type}</option>`).join("");
  $("dexStats").textContent = `${LOGANMON.length} Loganmon loaded`;
}

function selectedSpecies() {
  const dex = Number($("speciesSelect").value || 1);
  return LOGANMON.find(m => m.dex === dex) || LOGANMON[0];
}

function updateSpeciesMeta() {
  currentSpecies = selectedSpecies();
  const mon = currentSpecies;
  $("speciesMeta").innerHTML = [
    ["Dex", `#${String(mon.dex).padStart(3,'0')}`],
    ["Name", mon.name],
    ["Type", mon.type],
    ["Replaces", mon.replaces],
    ["Role", rarityRole(mon)],
    ["Evolution", evolutionStage(mon)]
  ].map(([a,b]) => `<div><b>${a}</b><span>${escapeHtml(b)}</span></div>`).join("");
}

function buildBrief() {
  const mon = selectedSpecies();
  const archetype = archetypeByReplacement[mon.replaces] || "original creature based on its name and type";
  const custom = $("customNotes").value.trim();
  const prompt = `Create one original Loganmon creature concept for a Pokemon FireRed-style fan remake.

Species: ${mon.name}
Dex number: ${mon.dex}
Type: ${mon.type}
Replaces FireRed slot: ${mon.replaces}
Rarity/role based on replacement slot: ${rarityRole(mon)}
Evolution stage: ${evolutionStage(mon)}
Base design direction from replacement/name: ${archetype}
Type visual motifs: ${typeMotifText(mon.type)}
${custom ? `Extra user notes: ${custom}
` : ""}
Art direction: original creature only, not an existing Pokemon, high-quality monster battler design, front 3/4 battle view, full body, centered, strong readable silhouette, clean outline, expressive face, appealing proportions, simple light or transparent background, no trainer, no text, no logo, no UI. Make it polished enough to later convert into a 64x64 FireRed-compatible battle sprite. Preserve the species identity and make the design clearly match its name, type, rarity, and evolution stage.`;
  currentBrief = {
    app: "LoganCreations",
    version: "0.8",
    module: "Loganmon Brief Builder",
    species: mon,
    rarityRole: rarityRole(mon),
    evolutionStage: evolutionStage(mon),
    archetype,
    prompt
  };
  $("promptBox").value = prompt;
  $("briefTitle").textContent = `${mon.name} design prompt`;
  $("briefBadge").textContent = mon.type;
  return currentBrief;
}

function apiKey() { return localStorage.getItem(API_KEY_STORAGE) || ""; }
function updateApiStatus() {
  const key = apiKey();
  $("apiStatus").textContent = key ? "API key saved locally" : "API not saved";
  if (key && !$("apiKeyInput").value) $("apiKeyInput").value = key;
}

async function generateOpenAiImage() {
  const key = $("apiKeyInput").value.trim() || apiKey();
  const prompt = $("promptBox").value.trim();
  if (!key) return alert("Paste and save your OpenAI API key first.");
  if (!prompt) return alert("Generate or write a prompt first.");
  $("imageStatus").textContent = "Generating...";
  $("generateImageBtn").disabled = true;
  try {
    const response = await fetch("https://api.openai.com/v1/images/generations", {
      method: "POST",
      headers: { "Content-Type": "application/json", "Authorization": `Bearer ${key}` },
      body: JSON.stringify({
        model: $("imageModel").value,
        prompt,
        size: $("imageSize").value,
        quality: $("imageQuality").value,
        n: 1
      })
    });
    const data = await response.json();
    if (!response.ok) throw new Error(data.error?.message || "OpenAI image request failed.");
    const b64 = data.data?.[0]?.b64_json;
    if (!b64) throw new Error("No image was returned. Try a different model or prompt.");
    currentAiDataUrl = `data:image/png;base64,${b64}`;
    $("aiImage").src = currentAiDataUrl;
    $("aiImage").hidden = false;
    $("imageTitle").textContent = selectedSpecies().name + " concept";
    $("imageStatus").textContent = "Generated";
    loadImageToConverter(currentAiDataUrl);
  } catch (error) {
    console.error(error);
    alert(error.message || "Could not generate image.");
    $("imageStatus").textContent = "Error";
  } finally {
    $("generateImageBtn").disabled = false;
  }
}

function loadImageToConverter(dataUrl) {
  const img = new Image();
  img.onload = () => { sourceImage = img; drawSourcePreview(); convertSprite(); };
  img.src = dataUrl;
}

function activeCrop() {
  if (!sourceImage) return null;
  const zoom = Math.max(0.1, Number($("cropZoom").value) || 0.72);
  const cropSize = Math.min(sourceImage.width, sourceImage.height) / zoom;
  const centerX = sourceImage.width / 2 + Number($("offsetX").value || 0);
  const centerY = sourceImage.height / 2 + Number($("offsetY").value || 0);
  return { sx: centerX - cropSize / 2, sy: centerY - cropSize / 2, sw: cropSize, sh: cropSize };
}

function drawChecker(ctx, size) {
  ctx.fillStyle = "#120303";
  ctx.fillRect(0,0,size,size);
  ctx.fillStyle = "rgba(255,255,255,0.035)";
  const step = 12;
  for (let y=0;y<size;y+=step) for (let x=0;x<size;x+=step) if (((x+y)/step)%2===0) ctx.fillRect(x,y,step,step);
}

function drawSourcePreview() {
  sourceCtx.clearRect(0,0,192,192);
  drawChecker(sourceCtx, 192);
  if (!sourceImage) return;
  const crop = activeCrop();
  sourceCtx.imageSmoothingEnabled = true;
  sourceCtx.imageSmoothingQuality = "high";
  sourceCtx.drawImage(sourceImage, crop.sx, crop.sy, crop.sw, crop.sh, 0, 0, 192, 192);
}

function resetConverter() {
  $("cropZoom").value = "0.72";
  $("offsetX").value = "0";
  $("offsetY").value = "0";
  $("colorSteps").value = "0";
  $("outlineStrength").value = "0";
  $("contrast").value = "104";
  $("saturation").value = "105";
  $("converterMode").value = "clean";
  $("removeBg").checked = true;
  $("transparentBg").checked = true;
  drawSourcePreview();
  convertSprite();
}

function findSubjectBox() {
  if (!sourceImage) return null;
  const maxSide = 512;
  const scale = Math.min(1, maxSide / Math.max(sourceImage.width, sourceImage.height));
  const w = Math.max(1, Math.round(sourceImage.width * scale));
  const h = Math.max(1, Math.round(sourceImage.height * scale));
  const c = document.createElement("canvas");
  c.width = w; c.height = h;
  const cx = c.getContext("2d", { willReadFrequently: true });
  cx.drawImage(sourceImage, 0, 0, w, h);
  const img = cx.getImageData(0,0,w,h).data;
  const corners = [[0,0],[w-1,0],[0,h-1],[w-1,h-1]].map(([x,y]) => {
    const i=(y*w+x)*4; return [img[i],img[i+1],img[i+2],img[i+3]];
  });
  const bg = corners.reduce((a,p)=>[a[0]+p[0]/4,a[1]+p[1]/4,a[2]+p[2]/4,a[3]+p[3]/4],[0,0,0,0]);
  let minX=w, minY=h, maxX=0, maxY=0, found=false;
  for (let y=0;y<h;y++) for (let x=0;x<w;x++) {
    const i=(y*w+x)*4;
    const a=img[i+3];
    const diff=Math.abs(img[i]-bg[0])+Math.abs(img[i+1]-bg[1])+Math.abs(img[i+2]-bg[2]);
    const nonBg = a > 20 && (a < 245 || diff > 64);
    if (nonBg) { found=true; if(x<minX)minX=x; if(y<minY)minY=y; if(x>maxX)maxX=x; if(y>maxY)maxY=y; }
  }
  if (!found) return null;
  return { minX:minX/scale, minY:minY/scale, maxX:maxX/scale, maxY:maxY/scale };
}

function autoFitSubject() {
  const box = findSubjectBox();
  if (!box || !sourceImage) return;
  const bw = box.maxX - box.minX;
  const bh = box.maxY - box.minY;
  const longest = Math.max(bw, bh);
  const minDim = Math.min(sourceImage.width, sourceImage.height);
  const padding = 1.18;
  const zoom = Math.max(0.35, Math.min(2.4, minDim / (longest * padding)));
  const cx = (box.minX + box.maxX) / 2;
  const cy = (box.minY + box.maxY) / 2;
  $("cropZoom").value = zoom.toFixed(2);
  $("offsetX").value = Math.round(cx - sourceImage.width / 2);
  $("offsetY").value = Math.round(cy - sourceImage.height / 2);
  drawSourcePreview();
  convertSprite();
}

function adjustChannel(v, contrast, saturation, avg) {
  return Math.max(0, Math.min(255, ((v - 128) * contrast + 128 - avg) * saturation + avg));
}

function bgDistance(r,g,b,bg) {
  return Math.abs(r-bg[0]) + Math.abs(g-bg[1]) + Math.abs(b-bg[2]);
}

function cleanBackground(ctx, size) {
  const img = ctx.getImageData(0,0,size,size);
  const d = img.data;
  const sample = [];
  const points = [[0,0],[size-1,0],[0,size-1],[size-1,size-1],[Math.floor(size/2),0],[0,Math.floor(size/2)],[size-1,Math.floor(size/2)]];
  for (const [x,y] of points) { const i=(y*size+x)*4; sample.push([d[i],d[i+1],d[i+2]]); }
  const bg = sample.reduce((a,p)=>[a[0]+p[0]/sample.length,a[1]+p[1]/sample.length,a[2]+p[2]/sample.length],[0,0,0]);
  for (let i=0;i<d.length;i+=4) {
    const r=d[i], g=d[i+1], b=d[i+2], a=d[i+3];
    const max=Math.max(r,g,b), min=Math.min(r,g,b);
    const lightFlat = max > 222 && (max-min) < 50;
    const closeToBg = bgDistance(r,g,b,bg) < 58 && max > 165;
    if (a < 20 || lightFlat || closeToBg) d[i+3]=0;
  }
  ctx.putImageData(img,0,0);
}

function processSpritePixels(ctx, size) {
  const img = ctx.getImageData(0,0,size,size);
  const d = img.data;
  const steps = Number($("colorSteps").value || 0);
  const mode = $("converterMode").value;
  const contrast = (Number($("contrast").value) || 100) / 100;
  const sat = (Number($("saturation").value) || 100) / 100;
  const forcedSteps = mode === "gba" ? 12 : mode === "pixel" ? Math.max(steps, 10) : steps;
  for (let i=0; i<d.length; i+=4) {
    if (d[i+3] < 16) continue;
    let r=d[i], g=d[i+1], b=d[i+2];
    const avg=(r+g+b)/3;
    r = adjustChannel(r, contrast, sat, avg);
    g = adjustChannel(g, contrast, sat, avg);
    b = adjustChannel(b, contrast, sat, avg);
    if (forcedSteps > 1) {
      const q = 255 / (forcedSteps - 1);
      r = Math.round(r / q) * q;
      g = Math.round(g / q) * q;
      b = Math.round(b / q) * q;
    }
    d[i]=r; d[i+1]=g; d[i+2]=b;
  }
  ctx.putImageData(img,0,0);
}

function convertSprite() {
  if (!sourceImage) return;
  const outSize = Number($("spriteSize").value);
  const mode = $("converterMode").value;
  $("spriteStatus").textContent = `${outSize}x${outSize} ${mode} target`;
  drawSourcePreview();

  const crop = activeCrop();
  const superScale = mode === "clean" ? 4 : mode === "gba" ? 3 : 2;
  const hiSize = outSize * superScale;
  const hi = document.createElement("canvas");
  hi.width = hiSize; hi.height = hiSize;
  const h = hi.getContext("2d", { willReadFrequently: true });
  h.imageSmoothingEnabled = true;
  h.imageSmoothingQuality = "high";
  if (!$("transparentBg").checked) { h.fillStyle = "#f8efe2"; h.fillRect(0,0,hiSize,hiSize); }
  h.drawImage(sourceImage, crop.sx, crop.sy, crop.sw, crop.sh, 0, 0, hiSize, hiSize);
  if ($("removeBg").checked) cleanBackground(h, hiSize);

  const work = document.createElement("canvas");
  work.width = outSize; work.height = outSize;
  const w = work.getContext("2d", { willReadFrequently: true });
  w.imageSmoothingEnabled = mode === "clean";
  w.imageSmoothingQuality = "high";
  if (!$("transparentBg").checked) { w.fillStyle = "#f8efe2"; w.fillRect(0,0,outSize,outSize); }
  w.drawImage(hi, 0, 0, hiSize, hiSize, 0, 0, outSize, outSize);
  processSpritePixels(w, outSize);
  const outline = Number($("outlineStrength").value || 0);
  if (outline > 0) addOutsideOutline(w, outSize, outline);

  spriteCanvas.width = 192; spriteCanvas.height = 192;
  spriteCtx.clearRect(0,0,192,192);
  drawChecker(spriteCtx, 192);
  spriteCtx.imageSmoothingEnabled = false;
  spriteCtx.drawImage(work,0,0,outSize,outSize,0,0,192,192);
  spriteDataUrl = work.toDataURL("image/png");
  const crush = Number($("colorSteps").value || 0);
  $("converterHint").textContent = `Converted from the original source to ${outSize}x${outSize}. Palette crush: ${crush ? crush : "off"}. Outline: ${outline}.`;
}

function addOutsideOutline(ctx, size, strength) {
  const img = ctx.getImageData(0,0,size,size);
  const src = new Uint8ClampedArray(img.data);
  const dst = img.data;
  for (let y=0;y<size;y++) {
    for (let x=0;x<size;x++) {
      const idx=(y*size+x)*4;
      if (src[idx+3] > 15) continue;
      let near=false;
      for (let oy=-strength;oy<=strength;oy++) for (let ox=-strength;ox<=strength;ox++) {
        if (!ox && !oy) continue;
        const nx=x+ox, ny=y+oy;
        if (nx<0||ny<0||nx>=size||ny>=size) continue;
        if (src[(ny*size+nx)*4+3] > 70) near=true;
      }
      if (near) { dst[idx]=18; dst[idx+1]=12; dst[idx+2]=12; dst[idx+3]=255; }
    }
  }
  ctx.putImageData(img,0,0);
}

function loadVault() { try { return JSON.parse(localStorage.getItem(VAULT_KEY) || "[]"); } catch { return []; } }
function saveVault() { localStorage.setItem(VAULT_KEY, JSON.stringify(vault)); }
function addAsset(asset) {
  vault.unshift({ id:`asset_${Date.now()}_${Math.random().toString(16).slice(2,8)}`, createdAt:new Date().toISOString(), ...asset });
  try { saveVault(); } catch (e) { vault.shift(); alert("Could not save. Browser storage is full. Download the file instead or export/clear old vault items."); }
  renderVault();
}
function escapeHtml(v) { return String(v ?? "").replace(/[&<>"']/g, ch => ({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[ch])); }
function slug(v) { return String(v||"asset").toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-|-$/g,"") || "asset"; }
function dataUrlToBlob(dataUrl) { const [head,b64] = dataUrl.split(","); const mime=head.match(/data:(.*?);/)?.[1]||"application/octet-stream"; const bin=atob(b64); const bytes=new Uint8Array(bin.length); for(let i=0;i<bin.length;i++) bytes[i]=bin.charCodeAt(i); return new Blob([bytes],{type:mime}); }
function downloadBlob(filename, blob) { const url=URL.createObjectURL(blob); const a=document.createElement("a"); a.href=url; a.download=filename; document.body.appendChild(a); a.click(); a.remove(); URL.revokeObjectURL(url); }
function formatBytes(bytes=0) { if(!bytes) return "0 B"; const u=["B","KB","MB","GB"]; const i=Math.min(Math.floor(Math.log(bytes)/Math.log(1024)),u.length-1); return `${(bytes/Math.pow(1024,i)).toFixed(i?1:0)} ${u[i]}`; }

function renderVault() {
  const q=$("vaultSearch").value.toLowerCase().trim(); const type=$("vaultType").value;
  const filtered=vault.filter(a=>(!type||a.type===type)&&(!q||`${a.name} ${a.description} ${(a.tags||[]).join(" ")}`.toLowerCase().includes(q)));
  $("vaultStats").textContent=`${vault.length} stored · ${filtered.length} showing`;
  $("vaultEmpty").hidden=filtered.length>0;
  $("vaultGrid").innerHTML=filtered.map(a=>`<article class="asset-card"><div class="asset-top">${a.dataUrl&&a.mime&&a.mime.startsWith("image/")?`<img class="asset-thumb" src="${a.dataUrl}" alt="">`:`<div class="asset-icon">◆</div>`}<div><h3>${escapeHtml(a.name)}</h3><p>${escapeHtml(a.type)} · ${formatBytes(a.size)} · ${new Date(a.createdAt).toLocaleDateString()}</p></div></div><p>${escapeHtml(a.description||"")}</p><div class="asset-tags">${(a.tags||[]).map(t=>`<span>${escapeHtml(t)}</span>`).join("")}</div><div class="asset-actions"><button type="button" data-download="${a.id}">Download</button><button type="button" data-copy="${a.id}">Duplicate</button><button type="button" class="danger-action" data-remove="${a.id}">Remove</button></div></article>`).join("");
}

function openSection(section) {
  $("pipelinePanel").hidden = section !== "pipeline";
  $("vaultPanel").hidden = section !== "vault";
  if (section === "pipeline") { $("previewTitle").textContent="Loganmon Sprite Pipeline"; $("previewBadge").textContent="Working"; $("previewText").textContent="Generate a brief, create an AI image, then convert it into a FireRed-style sprite."; $("pipelinePanel").scrollIntoView({behavior:"smooth",block:"start"}); }
  if (section === "vault") { $("previewTitle").textContent="Asset Vault"; $("previewBadge").textContent="Working"; $("previewText").textContent="Download, duplicate, remove, and back up saved assets."; renderVault(); $("vaultPanel").scrollIntoView({behavior:"smooth",block:"start"}); }
}

document.querySelectorAll("[data-open]").forEach(btn=>btn.addEventListener("click",()=>openSection(btn.dataset.open)));
document.querySelectorAll("[data-placeholder]").forEach(btn=>btn.addEventListener("click",()=>{ $("previewTitle").textContent=btn.dataset.placeholder; $("previewBadge").textContent="Planned"; $("previewText").textContent=`${btn.dataset.placeholder} is planned. The working tool right now is the Loganmon Sprite Pipeline.`; }));
$("effectToggle").addEventListener("click",()=>document.body.classList.toggle("low-effects"));
$("speciesSelect").addEventListener("change",()=>{ updateSpeciesMeta(); buildBrief(); });
$("buildBriefBtn").addEventListener("click",buildBrief);
$("copyPromptBtn").addEventListener("click",async()=>{ if(!$("promptBox").value.trim()) buildBrief(); await navigator.clipboard.writeText($("promptBox").value); $("briefBadge").textContent="Copied"; });
$("saveBriefBtn").addEventListener("click",()=>{ const b=currentBrief||buildBrief(); addAsset({type:"brief",name:`${b.species.name} Design Brief`,description:`Prompt brief for ${b.species.name}`,tags:["brief",b.species.name,b.species.type],filename:`${slug(b.species.name)}-brief.json`,mime:"application/json",size:JSON.stringify(b).length,content:b}); });
$("saveKeyBtn").addEventListener("click",()=>{ const key=$("apiKeyInput").value.trim(); if(!key) return alert("Paste a key first."); localStorage.setItem(API_KEY_STORAGE,key); updateApiStatus(); });
$("clearKeyBtn").addEventListener("click",()=>{ localStorage.removeItem(API_KEY_STORAGE); $("apiKeyInput").value=""; updateApiStatus(); });
$("generateImageBtn").addEventListener("click",generateOpenAiImage);
$("useAiForSpriteBtn").addEventListener("click",()=>{ if(!currentAiDataUrl) return alert("Generate an AI image first."); loadImageToConverter(currentAiDataUrl); });
$("downloadAiBtn").addEventListener("click",()=>{ if(!currentAiDataUrl) return alert("No AI image yet."); const name=selectedSpecies().name; downloadBlob(`${slug(name)}-concept.png`, dataUrlToBlob(currentAiDataUrl)); });
$("saveAiBtn").addEventListener("click",()=>{ if(!currentAiDataUrl) return alert("No AI image yet."); const blob=dataUrlToBlob(currentAiDataUrl); const mon=selectedSpecies(); addAsset({type:"concept",name:`${mon.name} Concept Image`,description:`AI concept image for ${mon.name}`,tags:["concept",mon.name,mon.type],filename:`${slug(mon.name)}-concept.png`,mime:"image/png",size:blob.size,dataUrl:currentAiDataUrl,content:currentBrief}); });
$("sourceUpload").addEventListener("change",()=>{ const file=$("sourceUpload").files[0]; if(!file) return; const reader=new FileReader(); reader.onload=()=>loadImageToConverter(reader.result); reader.readAsDataURL(file); });
["spriteSize","converterMode","cropZoom","offsetX","offsetY","colorSteps","outlineStrength","contrast","saturation","removeBg","transparentBg"].forEach(id=>$(id).addEventListener("input",convertSprite));
$("autoFitBtn").addEventListener("click",autoFitSubject);
$("resetConverterBtn").addEventListener("click",resetConverter);
$("convertSpriteBtn").addEventListener("click",convertSprite);
$("downloadSpriteBtn").addEventListener("click",()=>{ if(!spriteDataUrl) return alert("Convert a sprite first."); downloadBlob(`${slug(selectedSpecies().name)}-sprite-${$("spriteSize").value}.png`, dataUrlToBlob(spriteDataUrl)); });
$("saveSpriteBtn").addEventListener("click",()=>{ if(!spriteDataUrl) return alert("Convert a sprite first."); const blob=dataUrlToBlob(spriteDataUrl); const mon=selectedSpecies(); addAsset({type:"sprite",name:`${mon.name} ${$("spriteSize").value}x${$("spriteSize").value} Sprite`,description:`Converted FireRed-style sprite for ${mon.name}`,tags:["sprite",mon.name,mon.type,`${$("spriteSize").value}x${$("spriteSize").value}`],filename:`${slug(mon.name)}-sprite-${$("spriteSize").value}.png`,mime:"image/png",size:blob.size,dataUrl:spriteDataUrl,content:currentBrief}); });
$("importFile").addEventListener("click",()=>$("fileInput").click());
$("fileInput").addEventListener("change",()=>{ [...$("fileInput").files].forEach(file=>{ if(file.size>2.5*1024*1024) return alert(`${file.name} is too large for this local vault.`); const reader=new FileReader(); reader.onload=()=>addAsset({type:file.type.startsWith("image/")?"sprite":"file",name:file.name.replace(/\.[^/.]+$/,"") ,description:`Imported file: ${file.name}`,tags:["imported"],filename:file.name,mime:file.type||"application/octet-stream",size:file.size,dataUrl:reader.result}); reader.readAsDataURL(file); }); $("fileInput").value=""; });
$("exportVault").addEventListener("click",()=>downloadBlob("loganscreations-vault-backup.json",new Blob([JSON.stringify({app:"LoganCreations",version:"0.9",assets:vault},null,2)],{type:"application/json"})));
$("restoreVaultBtn").addEventListener("click",()=>$("restoreInput").click());
$("restoreInput").addEventListener("change",()=>{ const file=$("restoreInput").files[0]; if(!file) return; const reader=new FileReader(); reader.onload=()=>{ try{ const parsed=JSON.parse(reader.result); vault=Array.isArray(parsed)?parsed:parsed.assets; if(!Array.isArray(vault)) throw new Error("No assets array"); saveVault(); renderVault(); openSection("vault"); }catch{ alert("Could not restore that JSON backup."); } }; reader.readAsText(file); });
$("clearVault").addEventListener("click",()=>{ if(vault.length&&confirm("Remove every asset from this device vault?")){ vault=[]; saveVault(); renderVault(); } });
$("vaultSearch").addEventListener("input",renderVault); $("vaultType").addEventListener("input",renderVault);
$("vaultGrid").addEventListener("click",e=>{ const d=e.target.closest("[data-download]"), c=e.target.closest("[data-copy]"), r=e.target.closest("[data-remove]"); if(d){ const a=vault.find(x=>x.id===d.dataset.download); if(a) downloadBlob(a.filename||`${slug(a.name)}.asset`, a.dataUrl?dataUrlToBlob(a.dataUrl):new Blob([JSON.stringify(a.content||a,null,2)],{type:"application/json"})); } if(c){ const a=vault.find(x=>x.id===c.dataset.copy); if(a) addAsset({...a,id:undefined,createdAt:undefined,name:`${a.name} Copy`}); } if(r){ const a=vault.find(x=>x.id===r.dataset.remove); if(a&&confirm(`Remove "${a.name}"?`)){ vault=vault.filter(x=>x.id!==a.id); saveVault(); renderVault(); } } });

populateSpecies(); updateSpeciesMeta(); updateApiStatus(); buildBrief(); renderVault();
